package cn.intentforge.agent.core;

/**
 * One step in the coding plan generated by the planner stage.
 *
 * @param id stable step identifier
 * @param title short step title
 * @param description detailed step explanation
 * @param toolId optional recommended tool identifier
 * @param required whether the step is mandatory for completion
 */
public record PlanStep(
    String id,
    String title,
    String description,
    String toolId,
    boolean required
) {
  /**
   * Creates a validated plan step.
   */
  public PlanStep {
    id = cn.intentforge.common.util.ValidationSupport.requireText(id, "id");
    title = cn.intentforge.common.util.ValidationSupport.requireText(title, "title");
    description = cn.intentforge.common.util.ValidationSupport.requireText(description, "description");
    toolId = cn.intentforge.common.util.ValidationSupport.normalize(toolId);
  }
}
